import { FastifyPluginAsync } from 'fastify'
import { config } from '../../config.js'
import { decodeCursor, encodeCursor, paginatedResponse, paginationQuerySchema } from '../../pagination.js'
import { baseItemBodySchema, WRITE_RATE_LIMIT } from '../../schemas.js'

// When /v2 is released, add to onSend hook:
// reply.header('Deprecation', 'true')
// reply.header('Sunset', 'Sat, 01 Jan 2027 00:00:00 GMT')
// reply.header('Link', '</v2/status>; rel="successor-version"')

interface CreateItemBody {
  name: string
  price: number
}

const v1Routes: FastifyPluginAsync = async (fastify) => {
  // GET routes inherit the global 100 req/min default — read-only, no override needed
  fastify.get('/status', {
    config: { compress: false },
    schema: {
      summary: 'API v1 status',
      tags: ['v1'],
      response: {
        200: {
          type: 'object',
          properties: {
            version: { type: 'string' },
            status: { type: 'string' },
            timestamp: { type: 'string' }
          }
        }
      }
    }
  }, async () => ({
    version: '1',
    status: 'ok',
    timestamp: new Date().toISOString()
  }))

  // GET /items: cursor-based pagination over a stub item list
  fastify.get<{ Querystring: { limit?: number; cursor?: string } }>('/items', {
    schema: {
      summary: 'List v1 items',
      tags: ['v1'],
      querystring: paginationQuerySchema
    }
  }, async (request) => {
    const { limit = 20, cursor } = request.query
    const after = cursor ? decodeCursor(cursor, config.CURSOR_SECRET, (raw) => typeof raw.id === 'number' && Number.isFinite(raw.id)) : null
    const allItems = Array.from({ length: 50 }, (_, i) => ({
      id: i + 1,
      name: `Item ${i + 1}`,
      price: parseFloat(((i + 1) * 9.99).toFixed(2))
    }))
    const startId = (after?.id as number) ?? 0
    const filtered = allItems.filter(item => item.id > startId)
    const page = filtered.slice(0, limit)
    const nextCursor = filtered.length > limit ? encodeCursor({ id: page[page.length - 1].id }, config.CURSOR_SECRET) : null
    return paginatedResponse(page, nextCursor)
  })

  // POST routes that mutate state: enforced 30 req/min (tighter than global 100)
  fastify.post<{ Body: CreateItemBody }>('/items', {
    config: { rateLimit: WRITE_RATE_LIMIT },
    schema: {
      summary: 'Create a v1 item',
      tags: ['v1'],
      body: baseItemBodySchema,
      response: {
        200: {
          type: 'object',
          properties: {
            status: { type: 'string' },
            item: {
              type: 'object',
              properties: {
                name: { type: 'string' },
                price: { type: 'number' }
              }
            }
          }
        }
      }
    }
  }, async (request) => {
    return { status: 'created', item: request.body }
  })
}

export default v1Routes

import { describe, test, expect, beforeAll, afterAll } from 'vitest'
import type { FastifyInstance } from 'fastify'
import { buildApp } from './app.js'
import { WRITE_RATE_LIMIT } from './schemas.js'

let app: FastifyInstance

beforeAll(async () => {
  app = await buildApp()
})

afterAll(async () => {
  await app.close()
})

test('GET /health returns 200 with healthy status', async () => {
  const response = await app.inject({ method: 'GET', url: '/health' })
  expect(response.statusCode).toBe(200)
  const body = response.json()
  expect(body.status).toBe('healthy')
  expect(body.message).toBe('API is running')
  expect(typeof body.timestamp).toBe('string')
  expect(response.headers['cache-control']).toBe('no-store')
})

test('GET /health/live returns 200 with ok status', async () => {
  const response = await app.inject({ method: 'GET', url: '/health/live' })
  expect(response.statusCode).toBe(200)
  expect(response.json()).toEqual({ status: 'ok' })
})

test('GET /health/ready returns 503 before server.listen() is called', async () => {
  // server.listening is false when using inject() without calling listen() first
  // This is the 503 path: the server has not finished binding to a port
  const response = await app.inject({ method: 'GET', url: '/health/ready' })
  expect(response.statusCode).toBe(503)
  expect(response.json()).toEqual({ status: 'not_ready' })
})

test('GET /health/ready returns 200 once server is listening', async () => {
  // Use a separate app instance to avoid interfering with the shared test app.
  // Bind to a random port so server.listening becomes true, then verify ready.
  const listeningApp = await buildApp()
  await listeningApp.listen({ port: 0 })
  const response = await listeningApp.inject({ method: 'GET', url: '/health/ready' })
  expect(response.statusCode).toBe(200)
  expect(response.json()).toEqual({ status: 'ready' })
  await listeningApp.close()
})

test('GET /api/hello returns greeting message', async () => {
  const response = await app.inject({ method: 'GET', url: '/api/hello' })
  expect(response.statusCode).toBe(200)
  expect(response.json()).toEqual({ message: 'Hello from Fastify!' })
})

test('POST /api/items creates an item', async () => {
  const response = await app.inject({
    method: 'POST',
    url: '/api/items',
    payload: { name: 'Widget', price: 9.99 }
  })
  expect(response.statusCode).toBe(200)
  const body = response.json()
  expect(body.status).toBe('created')
  expect(body.item.name).toBe('Widget')
  expect(body.item.price).toBe(9.99)
})

test('GET /api/items/:id returns item by id', async () => {
  const response = await app.inject({ method: 'GET', url: '/api/items/42' })
  expect(response.statusCode).toBe(200)
  const body = response.json()
  expect(body.itemId).toBe(42)
  expect(body.name).toBe('Item 42')
  expect(body.price).toBe(99.99)
})

test('GET /api/items/:id with non-numeric id returns 404 Problem Detail', async () => {
  const response = await app.inject({ method: 'GET', url: '/api/items/abc' })
  expect(response.statusCode).toBe(404)
  expect(response.headers['content-type']).toContain('application/problem+json')
  const body = response.json()
  expect(body.status).toBe(404)
  expect(body.instance).toBe('/api/items/abc')
})

test('GET /api/items/:id with negative id returns 404 Problem Detail', async () => {
  const response = await app.inject({ method: 'GET', url: '/api/items/-1' })
  expect(response.statusCode).toBe(404)
  const body = response.json()
  expect(body.status).toBe(404)
})

test('X-Request-ID: valid UUID v4 is echoed back', async () => {
  const validUUID = '550e8400-e29b-4d00-a456-426614174000'
  const response = await app.inject({
    method: 'GET',
    url: '/health',
    headers: { 'x-request-id': validUUID }
  })
  expect(response.statusCode).toBe(200)
  expect(response.headers['x-request-id']).toBe(validUUID)
})

test('X-Request-ID: non-UUID value is rejected; a fresh UUID is generated', async () => {
  const response = await app.inject({
    method: 'GET',
    url: '/health',
    headers: { 'x-request-id': 'test-123' }
  })
  expect(response.statusCode).toBe(200)
  const reqId = response.headers['x-request-id']
  expect(reqId).not.toBe('test-123')
  expect(reqId).toMatch(/^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i)
})

test('X-Request-ID is generated when not provided', async () => {
  const response = await app.inject({ method: 'GET', url: '/health' })
  expect(response.statusCode).toBe(200)
  const reqId = response.headers['x-request-id']
  expect(typeof reqId).toBe('string')
  expect(reqId).toMatch(/^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/)
})

// v1/status covered in src/routes/v1/index.test.ts

test('POST /api/items with invalid body returns 400 Problem Detail', async () => {
  const response = await app.inject({
    method: 'POST',
    url: '/api/items',
    payload: { name: 'Widget' } // missing required 'price'
  })
  expect(response.statusCode).toBe(400)
  expect(response.headers['content-type']).toContain('application/problem+json')
  const body = response.json()
  expect(body.type).toBe('about:blank')
  expect(body.title).toBe('Bad Request')
  expect(body.status).toBe(400)
  expect(typeof body.detail).toBe('string')
  expect(body.detail.length).toBeGreaterThan(0)
})

test('GET /api/items/:id with id=0 returns 404 Problem Detail', async () => {
  const response = await app.inject({ method: 'GET', url: '/api/items/0' })
  expect(response.statusCode).toBe(404)
  expect(response.headers['content-type']).toContain('application/problem+json')
  const body = response.json()
  expect(body.type).toBe('about:blank')
  expect(body.title).toBe('Not Found')
  expect(body.status).toBe(404)
  expect(typeof body.detail).toBe('string')
  expect(body.instance).toBe('/api/items/0')
})

test.each(['/health', '/health/live', '/health/ready'])(
  'GET %s returns Cache-Control: no-store',
  async (url) => {
    const res = await app.inject({ method: 'GET', url })
    expect(res.headers['cache-control']).toBe('no-store')
  }
)

test.each(['/', '/health', '/health/live', '/health/ready', '/v1/status'])(
  'GET %s is not compressed',
  async (url) => {
    const res = await app.inject({ method: 'GET', url })
    expect(res.headers['content-encoding']).toBeUndefined()
  }
)

test('GET /v1/items with Accept-Encoding: gzip returns gzip-encoded response', async () => {
  // limit=50 ensures payload exceeds the 1024-byte compression threshold
  const res = await app.inject({
    method: 'GET',
    url: '/v1/items?limit=50',
    headers: { 'accept-encoding': 'gzip' }
  })
  expect(res.statusCode).toBe(200)
  expect(res.headers['content-encoding']).toBe('gzip')
})

// GET / serves dist/index.html when the file exists (HTML path is exercised here).
// The JSON fallback ({ message, health, docs }) executes only when dist/index.html is
// absent; that branch depends on config.NODE_ENV (not the buildApp nodeEnv option)
// for the `docs` field, so it is not separately testable without filesystem mocking.
test('GET / serves landing page with 200', async () => {
  const response = await app.inject({ method: 'GET', url: '/' })
  expect(response.statusCode).toBe(200)
  expect(response.headers['content-type']).toMatch(/html/)
})

// /docs/json is registered only when NODE_ENV !== 'production' (swaggerUi plugin conditional in app.ts)
test('GET /docs/json returns valid OpenAPI spec', async () => {
  const response = await app.inject({ method: 'GET', url: '/docs/json' })
  expect(response.statusCode).toBe(200)
  const spec = response.json()
  expect(spec.openapi).toBe('3.0.0')
  expect(spec.info).toBeDefined()
  expect(spec.paths).toBeDefined()
  expect(spec.paths['/v1/status']).toBeDefined()
})

test('POST /api/items with extra fields returns 400 (mass assignment prevention)', async () => {
  const response = await app.inject({
    method: 'POST',
    url: '/api/items',
    payload: { name: 'Widget', price: 9.99, role: 'admin' }
  })
  expect(response.statusCode).toBe(400)
})

test('POST with oversized body returns 413', async () => {
  const largePayload = { name: 'x'.repeat(2 * 1024 * 1024), price: 1 }
  const response = await app.inject({
    method: 'POST',
    url: '/api/items',
    payload: largePayload
  })
  expect(response.statusCode).toBe(413)
})

describe('POST /api/items input boundaries', () => {
  test('price: 0 is accepted (minimum boundary)', async () => {
    const res = await app.inject({
      method: 'POST', url: '/api/items',
      payload: { name: 'Widget', price: 0 }
    })
    expect(res.statusCode).toBe(200)
  })

  test('price: -0.01 is rejected with 400 (below minimum)', async () => {
    const res = await app.inject({
      method: 'POST', url: '/api/items',
      payload: { name: 'Widget', price: -0.01 }
    })
    expect(res.statusCode).toBe(400)
  })

  test('name at maxLength (255 chars) is accepted', async () => {
    const res = await app.inject({
      method: 'POST', url: '/api/items',
      payload: { name: 'a'.repeat(255), price: 1 }
    })
    expect(res.statusCode).toBe(200)
  })

  test('name exceeding maxLength (256 chars) is rejected with 400', async () => {
    const res = await app.inject({
      method: 'POST', url: '/api/items',
      payload: { name: 'a'.repeat(256), price: 1 }
    })
    expect(res.statusCode).toBe(400)
  })

  test('optional description field is accepted and echoed back', async () => {
    const res = await app.inject({
      method: 'POST', url: '/api/items',
      payload: { name: 'Widget', price: 9.99, description: 'A test widget' }
    })
    expect(res.statusCode).toBe(200)
    expect(res.json().item.description).toBe('A test widget')
  })
})

describe('CORS', () => {
  test('production mode: CORS headers absent on cross-origin request', async () => {
    const prodApp = await buildApp({ nodeEnv: 'production' })
    const res = await prodApp.inject({
      method: 'GET',
      url: '/health/live',
      headers: { Origin: 'https://evil.example.com' }
    })
    expect(res.headers['access-control-allow-origin']).toBeUndefined()
    await prodApp.close()
  })

  test('non-production: CORS preflight returns 204 or 200', async () => {
    const devApp = await buildApp({ nodeEnv: 'development' })
    const res = await devApp.inject({
      method: 'OPTIONS',
      url: '/health/live',
      headers: {
        Origin: 'http://localhost:3000',
        'Access-Control-Request-Method': 'GET'
      }
    })
    expect([200, 204]).toContain(res.statusCode)
    await devApp.close()
  })

  test('non-production: Access-Control-Allow-Credentials header is not present', async () => {
    const devApp = await buildApp({ nodeEnv: 'development' })
    const res = await devApp.inject({
      method: 'GET',
      url: '/health/live',
      headers: { Origin: 'http://attacker.example.com' }
    })
    expect(res.headers['access-control-allow-credentials']).toBeUndefined()
    await devApp.close()
  })
})

describe('X-Request-ID on all response types', () => {
  const UUID_V4_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i

  test('404 response includes X-Request-ID matching UUID v4', async () => {
    const response = await app.inject({ method: 'GET', url: '/no-such-route' })
    expect(response.statusCode).toBe(404)
    expect(response.headers['x-request-id']).toBeDefined()
    expect(response.headers['x-request-id']).toMatch(UUID_V4_RE)
  })

  test('400 response includes X-Request-ID', async () => {
    const response = await app.inject({
      method: 'POST',
      url: '/api/items',
      payload: { name: 'Widget' } // missing required 'price'
    })
    expect(response.statusCode).toBe(400)
    expect(response.headers['x-request-id']).toBeDefined()
  })

  test('429 response includes X-Request-ID', async () => {
    const rateLimitApp = await buildApp()
    for (let i = 0; i < WRITE_RATE_LIMIT.max; i++) {
      await rateLimitApp.inject({ method: 'POST', url: '/v1/items', payload: { name: 'x', price: 1 } })
    }
    const response = await rateLimitApp.inject({ method: 'POST', url: '/v1/items', payload: { name: 'x', price: 1 } })
    expect(response.statusCode).toBe(429)
    expect(response.headers['x-request-id']).toBeDefined()
    await rateLimitApp.close()
  })
})

import { describe, test, expect, beforeAll, afterAll } from 'vitest'
import type { FastifyInstance } from 'fastify'
import { buildApp } from './app.js'
import { createProblemDetail } from './errors.js'

describe('createProblemDetail unit', () => {
  test('full shape: all five keys present with correct values', () => {
    const result = createProblemDetail(404, 'Not Found', 'Resource missing', '/requests/1')
    expect(result).toEqual({
      type: 'about:blank',
      title: 'Not Found',
      status: 404,
      detail: 'Resource missing',
      instance: '/requests/1',
    })
  })

  test('no instance: result does not have instance key', () => {
    const result = createProblemDetail(400, 'Bad Request', 'Invalid input')
    expect(result).not.toHaveProperty('instance')
  })

  test('type is always about:blank for multiple status codes', () => {
    expect(createProblemDetail(400, 'Bad Request', 'x').type).toBe('about:blank')
    expect(createProblemDetail(404, 'Not Found', 'x').type).toBe('about:blank')
    expect(createProblemDetail(500, 'Internal Server Error', 'x').type).toBe('about:blank')
  })

  test('statusCode stored as-is in status field', () => {
    expect(createProblemDetail(422, 'Unprocessable Entity', 'x').status).toBe(422)
  })
})

describe('Error handler – RFC 9457 Problem Details', () => {
  let app: FastifyInstance

  beforeAll(async () => {
    app = await buildApp()
  })

  afterAll(async () => {
    await app.close()
  })

  test('returns 404 with RFC 9457 shape for unknown routes', async () => {
    const res = await app.inject({ method: 'GET', url: '/does-not-exist' })
    expect(res.statusCode).toBe(404)
    const body = res.json()
    expect(body).toHaveProperty('type')
    expect(body).toHaveProperty('title')
    expect(body).toHaveProperty('status', 404)
  })

  test('returns 400 with RFC 9457 shape for schema validation errors', async () => {
    // POST /v1/items requires name (string) and price (number)
    // Sending an empty body triggers Fastify schema validation → 400
    const res = await app.inject({
      method: 'POST',
      url: '/v1/items',
      headers: { 'content-type': 'application/json' },
      payload: {},
    })
    expect(res.statusCode).toBe(400)
    const body = res.json()
    expect(body).toHaveProperty('type')
    expect(body).toHaveProperty('title')
    expect(body).toHaveProperty('status', 400)
  })

  test('returns 400 (not 500) for malformed base64 cursor in pagination', async () => {
    const res = await app.inject({
      method: 'GET',
      url: '/v1/items?cursor=NOT_VALID_BASE64!!!',
    })
    expect(res.statusCode).toBe(400)
    // Must be JSON (not HTML) and must not leak stack trace
    const body = res.json()
    expect(typeof body).toBe('object')
    expect(body).not.toHaveProperty('stack')
  })

  test('returns 401 for thrown error with statusCode 401', async () => {
    const testApp = await buildApp()
    testApp.get('/test-401', async () => {
      const err = new Error('Unauthorized') as Error & { statusCode: number }
      err.statusCode = 401
      throw err
    })
    const res = await testApp.inject({ method: 'GET', url: '/test-401' })
    expect(res.statusCode).toBe(401)
    const body = res.json()
    expect(body.type).toBeDefined()
    expect(body).not.toHaveProperty('stack')
    await testApp.close()
  })

  test('returns 500 JSON without stack trace for unhandled errors', async () => {
    // Register a throw route before the first inject (which triggers ready())
    const throwApp = await buildApp()
    throwApp.get('/test-error-handler-throw', async () => {
      throw new Error('boom')
    })

    const originalEnv = process.env.NODE_ENV
    try {
      process.env.NODE_ENV = 'production'

      const res = await throwApp.inject({
        method: 'GET',
        url: '/test-error-handler-throw',
      })

      // Must be 500
      expect(res.statusCode).toBe(500)
      // Must return application/problem+json, not HTML (Fastify's default fallback)
      const contentType = res.headers['content-type'] ?? ''
      expect(contentType).toContain('problem+json')
      // Must not leak internal stack trace in production
      const body = res.json()
      expect(body).not.toHaveProperty('stack')
    } finally {
      process.env.NODE_ENV = originalEnv
      await throwApp.close()
    }
  })
})

import { describe, test, expect, beforeEach, afterEach } from 'vitest'
import type { FastifyInstance } from 'fastify'
import { buildApp } from './app.js'
import { WRITE_RATE_LIMIT } from './schemas.js'

describe('Rate limiting', () => {
  let app: FastifyInstance

  beforeEach(async () => {
    app = await buildApp()
  })

  afterEach(async () => {
    await app.close()
  })

  test('POST /v1/items returns 429 with correct headers and body after exceeding 30 req/min limit', async () => {
    let response

    for (let i = 0; i <= WRITE_RATE_LIMIT.max; i++) {
      response = await app.inject({
        method: 'POST',
        url: '/v1/items',
        payload: { name: 'test', price: 1 },
      })
    }

    expect(response!.statusCode).toBe(429)
    expect(response!.headers['x-ratelimit-limit']).toBeDefined()
    expect(response!.headers['x-ratelimit-remaining']).toBe('0')
    expect(response!.headers['retry-after']).toBeDefined()

    expect(response!.headers['content-type']).toContain('application/problem+json')
    const body = response!.json()
    expect(body).toHaveProperty('type')
    expect(body).toHaveProperty('title')
    expect(body).toHaveProperty('status', 429)
    expect(typeof body.detail).toBe('string')
  })

  test('GET /v1/status returns 429 after exceeding global 100 req/min limit', async () => {
    let response

    for (let i = 0; i < 101; i++) {
      response = await app.inject({
        method: 'GET',
        url: '/v1/status',
      })
    }

    expect(response!.statusCode).toBe(429)
  })
})

describe('POST /api/items rate limiting', () => {
  let app: FastifyInstance

  beforeEach(async () => { app = await buildApp() })
  afterEach(async () => { await app.close() })

  test('returns 429 after exceeding 30 req/min limit', async () => {
    let response
    for (let i = 0; i <= WRITE_RATE_LIMIT.max; i++) {
      response = await app.inject({
        method: 'POST',
        url: '/api/items',
        payload: { name: 'test', price: 1 },
      })
    }
    expect(response!.statusCode).toBe(429)
    expect(response!.headers['x-ratelimit-limit']).toBeDefined()
    expect(response!.headers['retry-after']).toBeDefined()
    expect(response!.headers['content-type']).toContain('application/problem+json')
    const body = response!.json()
    expect(body).toHaveProperty('type')
    expect(body).toHaveProperty('title')
    expect(body).toHaveProperty('status', 429)
    expect(typeof body.detail).toBe('string')
  })
})

describe('Health probe rate-limit exemption', () => {
  let app: FastifyInstance

  beforeEach(async () => {
    app = await buildApp()
    // /health/ready checks server.listening — must bind before injecting
    await app.listen({ port: 0 })
  })
  afterEach(async () => { await app.close() })

  test.each(['/health', '/health/live', '/health/ready'])(
    '%s returns 200 after global rate limit is exhausted',
    async (url) => {
      for (let i = 0; i < 100; i++) {
        await app.inject({ method: 'GET', url: '/api/hello' })
      }
      const res = await app.inject({ method: 'GET', url })
      expect(res.statusCode).toBe(200)
    }
  )
})

import { describe, test, expect } from 'vitest'
import { encodeCursor, decodeCursor, paginatedResponse, paginationQuerySchema } from './pagination.js'

const TEST_SECRET = 'test-cursor-secret-replace-in-production'

describe('encodeCursor / decodeCursor', () => {
  test('round-trips a simple object', () => {
    const value = { id: 42, createdAt: '2024-01-01T00:00:00Z' }
    expect(decodeCursor(encodeCursor(value, TEST_SECRET), TEST_SECRET)).toEqual(value)
  })

  test('round-trips an object with various value types', () => {
    const value = { id: 'abc', score: 3.14, nested: { x: 1 } }
    expect(decodeCursor(encodeCursor(value, TEST_SECRET), TEST_SECRET)).toEqual(value)
  })

  test('produces a base64url string (no +, /, = characters)', () => {
    const encoded = encodeCursor({ id: 1 }, TEST_SECRET)
    expect(encoded).not.toMatch(/[+/=]/)
  })

  test('produces a payload.signature format with a single dot separator', () => {
    const encoded = encodeCursor({ id: 1 }, TEST_SECRET)
    const parts = encoded.split('.')
    expect(parts).toHaveLength(2)
    expect(parts[0].length).toBeGreaterThan(0)
    expect(parts[1].length).toBeGreaterThan(0)
  })

  test('throws a 400 error on invalid base64url input', () => {
    const err = (() => { try { decodeCursor('!!!invalid!!!', TEST_SECRET) } catch (e) { return e } })() as Error & { statusCode: number }
    expect(err).toBeInstanceOf(Error)
    expect(err.statusCode).toBe(400)
  })

  test('throws a 400 error on valid base64 but missing signature', () => {
    const badCursor = Buffer.from('not-json').toString('base64url')
    const err = (() => { try { decodeCursor(badCursor, TEST_SECRET) } catch (e) { return e } })() as Error & { statusCode: number }
    expect(err).toBeInstanceOf(Error)
    expect(err.statusCode).toBe(400)
  })

  test('throws a 400 error when signature does not match (tampered cursor)', () => {
    const original = encodeCursor({ id: 1 }, TEST_SECRET)
    const dotIndex = original.lastIndexOf('.')
    const tamperedPayload = Buffer.from(JSON.stringify({ id: 9999 })).toString('base64url')
    const forged = `${tamperedPayload}.${original.slice(dotIndex + 1)}`
    const err = (() => { try { decodeCursor(forged, TEST_SECRET) } catch (e) { return e } })() as Error & { statusCode: number }
    expect(err).toBeInstanceOf(Error)
    expect(err.statusCode).toBe(400)
    expect(err.message).toContain('signature mismatch')
  })

  test('throws a 400 error when cursor re-encoded without the secret', () => {
    const raw = Buffer.from(JSON.stringify({ id: 42 })).toString('base64url')
    const wrongSig = Buffer.from('invalidsig').toString('base64url')
    const forged = `${raw}.${wrongSig}`
    const err = (() => { try { decodeCursor(forged, TEST_SECRET) } catch (e) { return e } })() as Error & { statusCode: number }
    expect(err).toBeInstanceOf(Error)
    expect(err.statusCode).toBe(400)
  })
})

describe('paginatedResponse', () => {
  test('wraps items in data envelope with pagination info', () => {
    const items = [{ id: 1 }, { id: 2 }]
    const cursor = encodeCursor({ id: 2 }, TEST_SECRET)
    const result = paginatedResponse(items, cursor)
    expect(result).toEqual({
      data: items,
      pagination: { nextCursor: cursor, hasMore: true }
    })
  })

  test('returns hasMore: false and nextCursor: null when no next cursor', () => {
    const result = paginatedResponse([{ id: 1 }], null)
    expect(result.pagination.hasMore).toBe(false)
    expect(result.pagination.nextCursor).toBeNull()
  })

  test('handles empty array with null cursor', () => {
    const result = paginatedResponse([], null)
    expect(result).toEqual({
      data: [],
      pagination: { nextCursor: null, hasMore: false }
    })
  })

  test('handles empty array with a cursor (edge case: filtered page)', () => {
    const cursor = encodeCursor({ id: 99 }, TEST_SECRET)
    const result = paginatedResponse([], cursor)
    expect(result.data).toEqual([])
    expect(result.pagination.hasMore).toBe(true)
    expect(result.pagination.nextCursor).toBe(cursor)
  })
})

describe('paginationQuerySchema', () => {
  test('defines limit with min 1 and max 100', () => {
    const limit = paginationQuerySchema.properties.limit
    expect(limit.minimum).toBe(1)
    expect(limit.maximum).toBe(100)
    expect(limit.default).toBe(20)
  })

  test('defines cursor as a string property', () => {
    const cursor = paginationQuerySchema.properties.cursor
    expect(cursor.type).toBe('string')
  })

  test('is a valid JSON schema object type', () => {
    expect(paginationQuerySchema.type).toBe('object')
  })
})

describe('decodeCursor with validator', () => {
  const isNumericId = (raw: Record<string, unknown>) => typeof raw.id === 'number' && Number.isFinite(raw.id)

  test('accepts a valid cursor when validator passes', () => {
    const cursor = encodeCursor({ id: 42 }, TEST_SECRET)
    expect(decodeCursor(cursor, TEST_SECRET, isNumericId)).toEqual({ id: 42 })
  })

  test('throws 400 when id is null', () => {
    const cursor = encodeCursor({ id: null }, TEST_SECRET)
    const err = (() => { try { decodeCursor(cursor, TEST_SECRET, isNumericId) } catch (e) { return e } })() as Error & { statusCode: number }
    expect(err).toBeInstanceOf(Error)
    expect(err.statusCode).toBe(400)
    expect(err.message).toContain('unexpected payload shape')
  })

  test('throws 400 when id is a string', () => {
    const cursor = encodeCursor({ id: 'xss' }, TEST_SECRET)
    const err = (() => { try { decodeCursor(cursor, TEST_SECRET, isNumericId) } catch (e) { return e } })() as Error & { statusCode: number }
    expect(err).toBeInstanceOf(Error)
    expect(err.statusCode).toBe(400)
    expect(err.message).toContain('unexpected payload shape')
  })

  test('throws 400 when id is Infinity', () => {
    // JSON.stringify coerces Infinity to null, so encode manually — also lacks a signature
    const cursor = Buffer.from(JSON.stringify({ id: null })).toString('base64url')
    const err = (() => { try { decodeCursor(cursor, TEST_SECRET, isNumericId) } catch (e) { return e } })() as Error & { statusCode: number }
    expect(err.statusCode).toBe(400)
  })

  test('without validator, still decodes payloads with null id', () => {
    const cursor = encodeCursor({ id: null }, TEST_SECRET)
    expect(decodeCursor(cursor, TEST_SECRET)).toEqual({ id: null })
  })
})

describe('pagination edge cases', () => {
  test('decodeCursor throws 400 for empty string', () => {
    const err = (() => { try { decodeCursor('', TEST_SECRET) } catch (e) { return e } })() as Error & { statusCode: number }
    expect(err).toBeInstanceOf(Error)
    expect(err.statusCode).toBe(400)
  })

  test('encodeCursor/decodeCursor roundtrips unicode and special characters', () => {
    const value = { name: 'héllo wörld 🎉', query: "<>&'" }
    expect(decodeCursor(encodeCursor(value, TEST_SECRET), TEST_SECRET)).toEqual(value)
  })

  test('encodeCursor/decodeCursor roundtrips arrays and null values', () => {
    const value = { tags: ['a', 'b', 'c'], count: 0, extra: null }
    expect(decodeCursor(encodeCursor(value, TEST_SECRET), TEST_SECRET)).toEqual(value)
  })

  test('paginatedResponse preserves all items when nextCursor is null', () => {
    const items = [{ id: 1 }, { id: 2 }, { id: 3 }]
    const result = paginatedResponse(items, null)
    expect(result.data).toEqual(items)
    expect(result.pagination.nextCursor).toBeNull()
    expect(result.pagination.hasMore).toBe(false)
  })

  test('paginationQuerySchema cursor field is optional (no required constraint)', () => {
    const schema = paginationQuerySchema as unknown as { required?: string[] }
    const required = schema.required ?? []
    expect(required).not.toContain('cursor')
  })
})

import { describe, test, expect, beforeAll, afterAll } from 'vitest'
import type { FastifyInstance } from 'fastify'
import { buildApp } from './app.js'

let app: FastifyInstance

beforeAll(async () => {
  app = await buildApp()
})

afterAll(async () => {
  await app.close()
})

describe('Helmet security headers', () => {
  const routes = ['/health', '/health/live', '/v1/status', '/api/hello', '/']

  test.each(routes)('GET %s sets X-Content-Type-Options: nosniff', async (url) => {
    const res = await app.inject({ method: 'GET', url })
    expect(res.headers['x-content-type-options']).toBe('nosniff')
  })

  test.each(routes)('GET %s sets X-Frame-Options to SAMEORIGIN or DENY', async (url) => {
    const res = await app.inject({ method: 'GET', url })
    const xfo = res.headers['x-frame-options'] as string | undefined
    expect(xfo).toBeDefined()
    expect(['SAMEORIGIN', 'DENY']).toContain(xfo)
  })

  test.each(routes)('GET %s sets X-DNS-Prefetch-Control: off', async (url) => {
    const res = await app.inject({ method: 'GET', url })
    expect(res.headers['x-dns-prefetch-control']).toBe('off')
  })

  test.each(routes)('GET %s includes a Content-Security-Policy header', async (url) => {
    const res = await app.inject({ method: 'GET', url })
    expect(res.headers['content-security-policy']).toBeDefined()
    expect(typeof res.headers['content-security-policy']).toBe('string')
    expect((res.headers['content-security-policy'] as string).length).toBeGreaterThan(0)
  })
})

